//
//  RepairTicketConfirmationView.swift
//  RSMS
//
//  Shown inline inside RepairIntakeView after the ticket is created.
//  Displays the ticket number generated by the DB trigger (trg_ast_number)
//  so the IC can write it on the physical item before dispatching.
//
//  NEW FILE — place in RSMS/Features/Inventory/Repairs/
//

import SwiftUI

struct RepairTicketConfirmationView: View {

    let ticket: ServiceTicketDTO
    let onDone: () -> Void

    var body: some View {
        ScrollView(showsIndicators: false) {
            VStack(spacing: AppSpacing.xl) {

                // ── Success Icon ──────────────────────────────────────────
                VStack(spacing: AppSpacing.sm) {
                    ZStack {
                        Circle()
                            .fill(AppColors.success.opacity(0.1))
                            .frame(width: 84, height: 84)
                        Image(systemName: "checkmark.circle.fill")
                            .font(.system(size: 46))
                            .foregroundColor(AppColors.success)
                    }

                    Text("Ticket Created")
                        .font(AppTypography.heading1)
                        .foregroundColor(AppColors.textPrimaryDark)

                    Text("The repair has been logged and is now tracked in the system.")
                        .font(AppTypography.bodySmall)
                        .foregroundColor(AppColors.textSecondaryDark)
                        .multilineTextAlignment(.center)
                        .padding(.horizontal, AppSpacing.lg)
                }
                .padding(.top, AppSpacing.xl)

                // ── Ticket Number Hero ────────────────────────────────────
                VStack(spacing: AppSpacing.xs) {
                    Text("TICKET NUMBER")
                        .font(AppTypography.overline)
                        .tracking(2)
                        .foregroundColor(AppColors.textSecondaryDark)
                    Text(ticket.displayTicketNumber)
                        .font(.system(size: 28, weight: .bold, design: .monospaced))
                        .foregroundColor(AppColors.accent)
                        .padding(.horizontal, AppSpacing.lg)
                        .padding(.vertical, AppSpacing.sm)
                        .background(
                            RoundedRectangle(cornerRadius: AppSpacing.radiusMedium)
                                .fill(AppColors.accent.opacity(0.07))
                                .overlay(
                                    RoundedRectangle(cornerRadius: AppSpacing.radiusMedium)
                                        .stroke(AppColors.accent.opacity(0.25), lineWidth: 1)
                                )
                        )
                }

                // ── Details Card ──────────────────────────────────────────
                VStack(spacing: 0) {
                    detailRow(label: "TYPE",
                              value: ticket.ticketType.displayName,
                              icon: ticket.ticketType.icon)
                    rowDivider
                    statusRow
                    if let notes = ticket.conditionNotes, !notes.isEmpty {
                        rowDivider
                        detailRow(label: "CONDITION", value: notes, multiline: true)
                    }
                    if let cost = ticket.estimatedCost {
                        rowDivider
                        detailRow(label: "EST. COST", value: String(format: "USD %.2f", cost))
                    }
                    if let sla = ticket.slaDueDate {
                        rowDivider
                        detailRow(label: "SLA DUE", value: formattedSLA(sla))
                    }
                    rowDivider
                    detailRow(label: "CREATED",
                              value: ticket.createdAt.formatted(date: .abbreviated, time: .shortened))
                }
                .background(
                    RoundedRectangle(cornerRadius: AppSpacing.radiusLarge)
                        .fill(AppColors.backgroundSecondary)
                        .overlay(
                            RoundedRectangle(cornerRadius: AppSpacing.radiusLarge)
                                .stroke(AppColors.border.opacity(0.4), lineWidth: 0.75)
                        )
                )

                // ── Label Reminder ────────────────────────────────────────
                HStack(spacing: AppSpacing.sm) {
                    Image(systemName: "tag.fill")
                        .foregroundColor(AppColors.accent)
                        .font(.system(size: 14))
                    Text("Attach a label with **\(ticket.displayTicketNumber)** to the physical item before dispatching to the service centre.")
                        .font(AppTypography.caption)
                        .foregroundColor(AppColors.textSecondaryDark)
                        .fixedSize(horizontal: false, vertical: true)
                }
                .padding(AppSpacing.sm)
                .background(
                    RoundedRectangle(cornerRadius: AppSpacing.radiusMedium)
                        .fill(AppColors.accent.opacity(0.06))
                        .overlay(
                            RoundedRectangle(cornerRadius: AppSpacing.radiusMedium)
                                .stroke(AppColors.accent.opacity(0.18), lineWidth: 1)
                        )
                )

                // ── Done Button ───────────────────────────────────────────
                Button(action: onDone) {
                    Text("Done")
                        .font(AppTypography.buttonPrimary)
                        .foregroundColor(.white)
                        .frame(maxWidth: .infinity)
                        .padding(.vertical, 16)
                        .background(
                            RoundedRectangle(cornerRadius: AppSpacing.radiusLarge)
                                .fill(AppColors.accent)
                        )
                }

                Spacer(minLength: AppSpacing.xxxl)
            }
            .padding(.horizontal, AppSpacing.screenHorizontal)
        }
    }

    // MARK: - Row Helpers

    private func detailRow(
        label: String,
        value: String,
        icon: String? = nil,
        multiline: Bool = false
    ) -> some View {
        HStack(alignment: multiline ? .top : .center, spacing: AppSpacing.sm) {
            Text(label)
                .font(AppTypography.overline)
                .tracking(0.8)
                .foregroundColor(AppColors.textSecondaryDark)
                .frame(width: 90, alignment: .leading)

            Spacer()

            HStack(spacing: 5) {
                if let icon {
                    Image(systemName: icon)
                        .font(.system(size: 12))
                        .foregroundColor(AppColors.accent)
                }
                Text(value)
                    .font(AppTypography.label)
                    .foregroundColor(AppColors.textPrimaryDark)
                    .multilineTextAlignment(multiline ? .leading : .trailing)
                    .lineLimit(multiline ? 4 : 1)
            }
            .frame(maxWidth: 200, alignment: .trailing)
        }
        .padding(.horizontal, AppSpacing.cardPadding)
        .padding(.vertical, AppSpacing.sm)
    }

    private var statusRow: some View {
        HStack {
            Text("STATUS")
                .font(AppTypography.overline)
                .tracking(0.8)
                .foregroundColor(AppColors.textSecondaryDark)
                .frame(width: 90, alignment: .leading)
            Spacer()
            let s = ticket.ticketStatus
            Text(s.displayName)
                .font(AppTypography.actionSmall)
                .foregroundColor(s.statusColor)
                .padding(.horizontal, 10)
                .padding(.vertical, 4)
                .background(s.statusColor.opacity(0.12))
                .clipShape(Capsule())
        }
        .padding(.horizontal, AppSpacing.cardPadding)
        .padding(.vertical, AppSpacing.sm)
    }

    private var rowDivider: some View {
        Divider()
            .background(AppColors.border.opacity(0.3))
            .padding(.horizontal, AppSpacing.cardPadding)
    }

    // MARK: - SLA Formatter

    private func formattedSLA(_ raw: String) -> String {
        let f = ISO8601DateFormatter()
        f.formatOptions = [.withFullDate, .withDashSeparatorInDate]
        return f.date(from: raw).map { $0.formatted(date: .long, time: .omitted) } ?? raw
    }
}
